import pandas as pd
policy = {"cliente_id": "required", "telefono": "optional", "monto": "required"}
df = pd.DataFrame({
    "cliente_id": ["C001", None, "C003"],
    "telefono": [None, "999", "998"],
    "monto": [1.0, 2.0, None],
})
